1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Step[];
6	};
7	
8	const PROCESSING_FEE = 5;
9	const ITEM_BASE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	};
13	
14	const quotePremium = (step: Step): number => {
15	  if (step.items.length === 0) return PROCESSING_FEE;
16	  const base = ITEM_BASE[step.items[0].type];
17	  const firstSurcharge = base * 0.1;
18	  return base + firstSurcharge + PROCESSING_FEE;
19	};
20	
21	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
22	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
23	  return { results };
24	};
