const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
const ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const quotePremium = (step: Step): number => {
  if (step.items.length === 0) return PROCESSING_FEE;
  const base = ITEM_BASE[step.items[0].type];
  const firstContractSurcharge = base * FIRST_CONTRACT_SURCHARGE_RATE;
  return base + firstContractSurcharge + PROCESSING_FEE;
};
